const body = $input.first().json.body || {};
const events = Array.isArray(body.events) ? body.events : [];

const ddl = "CREATE TABLE IF NOT EXISTS dashboard_auth_events (id BIGINT UNSIGNED AUTO_INCREMENT PRIMARY KEY, occurred_at DATETIME NOT NULL, src_ip VARCHAR(45) NOT NULL, method VARCHAR(10), path VARCHAR(512), status SMALLINT NOT NULL, user_agent VARCHAR(512), had_auth TINYINT NOT NULL DEFAULT 0, bytes_sent INT, line_hash CHAR(64) NOT NULL UNIQUE, INDEX idx_occurred (occurred_at), INDEX idx_src_ip (src_ip), INDEX idx_status (status)) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4";

if (events.length === 0) {
  return [{ json: { sql: ddl + '; SELECT 0 AS inserted', eventCount: 0 } }];
}

const esc = (v) => {
  if (v === null || v === undefined) return 'NULL';
  return "'" + String(v).replace(/\\/g, '\\\\').replace(/'/g, "''") + "'";
};

const values = events.map(e => {
  return `(${esc(e.occurred_at)}, ${esc(e.src_ip)}, ${esc(e.method)}, ${esc(e.path)}, ${Number(e.status) || 0}, ${esc(e.user_agent)}, ${e.had_auth ? 1 : 0}, ${Number.isFinite(e.bytes_sent) ? e.bytes_sent : 'NULL'}, ${esc(e.line_hash)})`;
}).join(',\n');

const insert = `INSERT IGNORE INTO dashboard_auth_events (occurred_at, src_ip, method, path, status, user_agent, had_auth, bytes_sent, line_hash) VALUES ${values}`;

return [{ json: { sql: ddl + ';\n' + insert, eventCount: events.length } }];

const rows = $input.all().map(i => i.json).filter(r => r && r.occurred_at);

const byIp = new Map();
for (const r of rows) {
  const k = r.src_ip;
  let e = byIp.get(k);
  if (!e) { e = { ip: k, count: 0, real_attempts: 0, probes: 0, user_agents: new Set(), first_seen: r.occurred_at, last_seen: r.occurred_at }; byIp.set(k, e); }
  e.count++;
  if (r.had_auth) e.real_attempts++; else e.probes++;
  if (r.user_agent) e.user_agents.add(r.user_agent);
  if (r.occurred_at < e.first_seen) e.first_seen = r.occurred_at;
  if (r.occurred_at > e.last_seen) e.last_seen = r.occurred_at;
}
const by_ip = [...byIp.values()]
  .map(e => ({ ...e, user_agents: [...e.user_agents].slice(0, 5) }))
  .sort((a, b) => b.count - a.count)
  .slice(0, 20);

const byPath = new Map();
for (const r of rows) {
  const k = r.path || '(none)';
  byPath.set(k, (byPath.get(k) || 0) + 1);
}
const by_path = [...byPath.entries()]
  .map(([path, count]) => ({ path, count }))
  .sort((a, b) => b.count - a.count)
  .slice(0, 10);

const recent = rows.slice(0, 50).map(r => ({
  id: r.id,
  occurred_at: r.occurred_at,
  src_ip: r.src_ip,
  method: r.method,
  path: r.path,
  status: r.status,
  user_agent: r.user_agent,
  had_auth: !!r.had_auth
}));

const total = rows.length;
const real_attempts = rows.filter(r => r.had_auth).length;
const probes = total - real_attempts;

return [{ json: { total, real_attempts, probes, by_ip, by_path, recent, window_days: 7 } }];
